import math
class Solution:
    def repairCars(self, ranks, cars):
        def can(t):
            total = 0
            for r in ranks:
                total += math.isqrt(t // r)
                if total >= cars:
                    return True
            return total >= cars
        lo, hi = 1, min(ranks) * cars * cars
        while lo < hi:
            mid = (lo + hi) // 2
            if can(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

