function isqrt(x) {
    if (x <= 0) return 0;
    let s = Math.floor(Math.sqrt(x));
    while ((s + 1) * (s + 1) <= x) s++;
    while (s * s > x) s--;
    return s;
}
var repairCars = function(ranks, cars) {
    const minRank = Math.min(...ranks);
    let lo = 1, hi = minRank * cars * cars;
    const can = (t) => {
        let total = 0;
        for (const r of ranks) {
            total += isqrt(Math.floor(t / r));
            if (total >= cars) return true;
        }
        return total >= cars;
    };
    while (lo < hi) {
        const mid = Math.floor(lo + (hi - lo) / 2);
        if (can(mid)) hi = mid; else lo = mid + 1;
    }
    return lo;
};
